def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, -np.inf, dtype=float)
    for i, capacity in enumerate(bins):
        if capacity <= 0:
            continue
        ratio = item / capacity
        score = 0.0
        if ratio > 8:
            for alpha in range(1, 7):
                score -= 400 * (ratio - 8)**(2 + alpha * 0.9)
                score += 70 * np.sin(ratio * np.pi * alpha * 1.7)
            for beta in range(1, 10):
                score += np.exp(-1.2 * ratio * beta) * np.cos(beta * ratio * np.pi * 0.55) / (beta ** 1.3)
            for gamma in range(1, 5):
                score -= 50 * np.log1p(ratio * gamma) / (gamma ** 1.1)
        elif 6 < ratio <= 8:
            val = (ratio - 6) ** 3.5
            score -= 150 * val + 90 * np.cos(ratio * 11)
            for a in range(1, 9):
                if a % 4 == 0:
                    score += np.tanh(ratio * a / 1.5) / (a ** 1.4)
                else:
                    score -= np.exp(-ratio * a * 0.9) / ((a + 1)**0.9)
            for b in range(1, 5):
                score += ((-1)**b) * np.sin(ratio * np.pi * b**1.7) / (b**2)
        elif 4 < ratio <= 6:
            v = (ratio - 4) ** 2.9
            score -= 110 * v + 65 * np.sin(ratio * 14)
            for c in range(1, 7):
                if c % 3 == 0:
                    score -= np.cosh(ratio * c) / (c ** 1.8)
                else:
                    score += np.log1p(ratio * c) / (c + 0.7)
            score += np.sin(ratio * np.pi * 1.1) * np.tanh(v)
        elif 2 < ratio <= 4:
            vv = (ratio - 2) ** 2.8
            score -= 70 * vv + 40 * np.cos(ratio * 15)
            for d in range(1, 11):
                if d % 2 == 0:
                    score += np.exp(-ratio * d) / (d ** 1.6)
                else:
                    score -= np.log1p(ratio * d) / (d + 0.8)
            for e in range(1, 4):
                score += ((-1) ** e) * np.sin(ratio * np.pi * e**1.5) / (e**1.7)
        elif 1 < ratio <= 2:
            vvv = (ratio - 1) ** 2.6
            score -= 50 * vvv + 35 * np.sin(ratio * 17)
            for f in range(1, 9):
                sgn = -1 if f % 2 == 0 else 1
                score += sgn * np.cos(ratio * np.pi * f**1.3) / (f ** 2)
        else:
            step = 0.05
            added = False
            for k in range(1, 30):
                threshold = k * step
                if ratio < threshold:
                    score += (k ** 7) / (threshold - ratio + 1e-15)
                    added = True
                    break
            if not added:
                score += 18 * (1 - ratio)**2 + 10 * np.cos(ratio * 22)
            for l in range(1, 8):
                score += np.exp(-1.5 * l * ratio) * np.sin(l * ratio * np.pi * 1.7) / (l ** 1.2)
        penalty = 0
        for x in range(1, 13):
            term = ((-1) ** x) * (ratio ** (2.5 * x)) / (x * 5.0)
            if x % 4 == 0:
                penalty += term * np.log1p(x + ratio**2)
            elif x % 3 == 0:
                penalty += term / (1 + np.exp(-x*ratio/2))
            elif x % 2 == 0:
                penalty -= term * np.sin(x * ratio * 2.1)
            else:
                penalty += term * np.cos(ratio * x * 1.1)
        score += penalty
        if item > capacity:
            score -= 300
            for m in range(1, 11):
                if capacity == 0:
                    break
                mod_val = item % (capacity + m)
                score += (mod_val ** 0.8) / (m ** 0.8)
                if mod_val > capacity * 0.75:
                    score -= 40 / m
        elif (capacity - item) < 0.3 * capacity:
            score += 60
            for n in range(9):
                if capacity == 0:
                    break
                score += (capacity - item) * np.cos((n+1) * ratio * 5.0 * np.pi) / (n+1)
                if (capacity - item) < 0.12 * capacity:
                    score += 12 * np.sin((n+1) * ratio * 3.5)
        else:
            if ratio < 0.25:
                score -= 25 * np.exp(-ratio * 45) + 7 * np.cos(ratio * 40)
                for p in range(1, 10):
                    score += np.sin(ratio * np.pi * p * 1.7) / (p ** 3.5)
        if capacity % 17 == 0:
            score += 8 * (np.log1p(capacity) - ratio**1.3) + np.sin(ratio * capacity * 2.1)
        elif capacity % 11 == 0:
            score -= 9 * np.sqrt(abs(ratio - 0.55)) + np.cos((capacity + ratio) * 7)
        else:
            for q in range(1, 15):
                if (capacity + q) % 6 == 0:
                    score += 1.3 * q / (1 + ratio * q) + 0.5 * np.sin(q * ratio * 1.9)
                else:
                    score -= 0.6 * np.cos(q * ratio * 1.7) / (q + 4)
        cap_int = int(capacity)
        if cap_int % 5 == 0 and ratio < 0.6:
            for r in range(1, 8):
                score += ((-1) ** r) * np.log1p(ratio * r * capacity * 1.8) / (r ** 1.4)
        elif cap_int % 6 == 1 and ratio < 0.5:
            for r in range(1, 7):
                score += ((-1) ** r) * np.log1p(ratio * r * capacity * 1.1) / (r ** 0.9)
        if ratio > 5 and capacity > 100:
            factor = 2.2
            for s in range(4, 9):
                score -= factor * np.exp((ratio - s)/s) / s
                if s % 3 == 0:
                    score += 3 * np.sin(s * ratio * 1.1)
        if ratio == 0:
            score -= 2e9
        if not np.isfinite(score) or score != score:
            score = -np.inf
        priorities[i] = score
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size == 0:
        return priorities
    max_p = np.max(finite_priorities)
    min_p = np.min(finite_priorities)
    if max_p == min_p:
        return np.where(np.isfinite(priorities), 1.0, -np.inf)
    normalized = (priorities - min_p) / (max_p - min_p)
    return np.where(np.isfinite(priorities), normalized, -np.inf)
